CREATE VIEW "catalog"."category_list_view" AS (select "catalog"."category"."project_id", "catalog"."category"."id", "catalog"."category"."parent_id", "catalog"."category"."path", "catalog"."category"."depth", "catalog"."category"."handle", "catalog"."category"."default_sort", "catalog"."category"."default_sort_direction", "catalog"."category"."published_at", "catalog"."category"."created_at", "catalog"."category"."updated_at", "catalog"."category"."deleted_at", "catalog"."category"."revision", "catalog"."category"."products_count", "catalog"."category_translation"."locale", "catalog"."category_translation"."name" from "catalog"."category" inner join "catalog"."category_translation" on "catalog"."category_translation"."project_id" = "catalog"."category"."project_id" AND "catalog"."category_translation"."category_id" = "catalog"."category"."id");